import { css, cx } from '@emotion/css'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import RetractIcon from '@mui/icons-material/Redo'
import RefreshIcon from '@mui/icons-material/Refresh'
import FlipIcon from '@mui/icons-material/Sync'
import { Button, Dialog, DialogActions, DialogContent } from '@mui/material'
import PropTypes from 'prop-types'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'

export interface IGameToolbarProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const GameToolbar: React.FC<IGameToolbarProps> = props => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [gameStatus, pieces, mover, _action] = useGomokuStore(
    store => [store.state.gameStatus, store.state.pieces, store.state.mover, store.action],
    shallow,
  )

  const [restartDialogVisible, setRestartDialogVisible] = React.useState<boolean>(false)
  const actions = React.useMemo(
    () => ({
      flip: _action.flip,
      retract: _action.retract,
      restart: (): void => {
        setRestartDialogVisible(false)
        _action.restart()
      },
      start: (): void => {
        if (gameStatus === GameRunningStatus.PENDING || gameStatus === GameRunningStatus.FINISHED) {
          actions.restart()
        } else {
          setRestartDialogVisible(true)
        }
      },
      closeDialog: (): void => setRestartDialogVisible(false),
    }),
    [_action, gameStatus],
  )

  const classes = useStyles()
  const shouldEnableRetract: boolean =
    (gameStatus === GameRunningStatus.RUNNING || gameStatus === GameRunningStatus.FINISHED) &&
    !!pieces.find(piece => piece.p === mover)
  const shouldEnableFlip: boolean = gameStatus === GameRunningStatus.PENDING
  return (
    <div className={classes.toolbar}>
      <div className={cx(classes.item, classes.buttons)}>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<RefreshIcon />}
          onClick={actions.start}
        >
          New
        </Button>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<RetractIcon />}
          disabled={!shouldEnableRetract}
          onClick={actions.retract}
        >
          Retract
        </Button>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<FlipIcon />}
          disabled={!shouldEnableFlip}
          onClick={actions.flip}
        >
          Flip
        </Button>
      </div>
      <Dialog
        container={props.containerRef.current}
        open={restartDialogVisible}
        onClose={() => setRestartDialogVisible(false)}
        aria-labelledby="confirm-to-restart"
      >
        <DialogContent>Are you sure you want to start a new game?</DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={actions.closeDialog}>
            Cancel
          </Button>
          <Button color="primary" onClick={actions.restart}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

GameToolbar.propTypes = {
  containerRef: PropTypes.any.isRequired,
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  toolbar: css`
    display: block;
    max-width: min(90vw, 400px);
    margin: auto;
  `,
  item: css`
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: flex-start;
    margin: 1rem 0;
    > * {
      margin-right: 1rem;
    }
  `,
  buttons: css`
    justify-content: space-around;
    > button {
      margin: 0 4px;
    }
  `,
})
