import type { IGomokuPlayer, IPlayer } from '../../types'
import { GomokuPlayerType } from '../constant'
import { CleverComputerPlayer } from './CleverComputerPlayer'
import { HumanPlayer } from './HumanPlayer'
import { StupidComputerPlayer } from './StupidComputerPlayer'

export const createPlayer = (params: IGomokuPlayer): IPlayer => {
  switch (params.type) {
    case GomokuPlayerType.HUMAN:
      return new HumanPlayer()
    case GomokuPlayerType.COMPUTER:
      return new CleverComputerPlayer({
        MAX_ADJACENT: 5,
        MAX_DISTANCE_OF_NEIGHBOR: 2,
      })
    case GomokuPlayerType.COMPUTER_STUPID:
      return new StupidComputerPlayer()
  }
}
