import { css, cx, keyframes } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import { GomokuDrawer } from '../core/drawer/GomokuDrawer'
import type { IPreferenceSettingsProvider } from '../core/drawer/GomokuPieceDrawer'
import { GomokuPieceDrawer, defaultPreferenceSettings } from '../core/drawer/GomokuPieceDrawer'
import { useMover } from '../hook/useMover'

export interface IGomokuBoardProps {
  /**
   * Gomoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * CSS class name.
   */
  className?: string
}

export const GameBoard: React.FC<IGomokuBoardProps> = props => {
  const { overlay, className } = props
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [GOMOKU_SIZE, pieces, gameStatus, players] = useGomokuStore(
    ({ state }) => [state.MAX_ROW, state.pieces, state.gameStatus, state.players],
    shallow,
  )

  const canvasRef = React.useRef<HTMLCanvasElement>(null)
  const playersRef = useReactiveRef(players)
  const moverRef = useReactiveRef(useMover())

  const pieceDrawer = React.useMemo(() => {
    const getPreferenceSettings: IPreferenceSettingsProvider = id => {
      return {
        ...defaultPreferenceSettings[id],
        ...playersRef.current[id].preferenceSettings,
      }
    }
    return new GomokuPieceDrawer(getPreferenceSettings)
  }, [playersRef])
  const gomokuDrawer = React.useMemo(
    () =>
      new GomokuDrawer({
        canvas: canvasRef.current,
        lines: GOMOKU_SIZE,
        pieces: [],
        pieceDrawer,
        onClick(r: number, c: number) {
          if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
            const mover = moverRef.current
            void mover.move({ r, c })
          }
        },
      }),
    [GOMOKU_SIZE, moverRef, pieceDrawer],
  )

  React.useEffect(() => {
    gomokuDrawer.reset(canvasRef.current)
    return (): void => gomokuDrawer.destroy()
  }, [gomokuDrawer])

  React.useEffect(() => {
    gomokuDrawer.draw(pieces)
  }, [gomokuDrawer, pieces])

  const classes = useStyles()
  return (
    <div className={cx(classes.container, className)}>
      <div key="overlay" className={cx(classes.overlay, classes[`overlay_${gameStatus}`])}>
        {overlay}
      </div>
      <canvas ref={canvasRef} />
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => {
  return {
    container: css`
      position: relative;
      box-sizing: content-box;
      display: inline-block;
      width: 100%;
      height: 100%;
      padding: 0;
      border: 0;
      margin: 0;
      font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
    `,
    overlay: css`
      z-index: 2;
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      display: none;
      width: 100%;
      height: 100%;
      overflow: hidden;
      background: linear-gradient(
        45deg,
        hsl(30deg 20% 90% / 0.2),
        hsl(210deg 20% 100% / 0.3)
      );
    `,
    [`overlay_${GameRunningStatus.PENDING}`]: css`
      && {
        display: block;
        backdrop-filter: blur(1px);
      }
    `,
    [`overlay_${GameRunningStatus.RUNNING}`]: css`
      && {
        display: none;
      }
    `,
    [`overlay_${GameRunningStatus.PAUSED}`]: css`
      && {
        display: block;
        backdrop-filter: blur(4px);
      }
    `,
    [`overlay_${GameRunningStatus.FINISHED}`]: css`
      && {
        display: block;
        backdrop-filter: blur(4px);
        color: #ff00ff;
        animation: 1s 0s ${animations.finished} ease-in-out;
      }
    `,
  }
}

const animations = {
  finished: keyframes`
    0% {
      transform: translate(0, -100px);
    }
    80% {
      transform: translate(0, 20px);
    }
    90% {
      transform: translate(0, -10px);
    }
    95% {
      transform: translate(0, 2px);
    }
    100% {
      transform: translate(0, 0);
    }
  `,
}
