import { css } from '@emotion/css'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import type { GomokuPlayerType } from '../core/constant'
import { GameSettingsGomokuSize } from './GameSettingsGomokuSize'
import { GameSettingsPlayer } from './GameSettingsPlayer'

export const GameSettings: React.FC = () => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [MAX_ROW, players, gameStatus, _action] = useGomokuStore(
    store => [store.state.MAX_ROW, store.state.players, store.state.gameStatus, store.action],
    shallow,
  )

  const actions = React.useMemo(
    () => ({
      onSizeChange: (size: number): void => _action.reset({ MAX_ROW: size, MAX_COL: size }),
      onPlayerChange: (id: number, type?: GomokuPlayerType, name?: string): void => {
        _action.resetPlayer(id, { type, name })
      },
    }),
    [_action],
  )

  const isPending: boolean = gameStatus === GameRunningStatus.PENDING
  const classes = useStyles()

  return (
    <div className={classes.container}>
      <GameSettingsGomokuSize
        className={classes.item}
        size={MAX_ROW}
        disabled={!isPending}
        onSizeChange={actions.onSizeChange}
      />
      {players.map((player, playerId) => (
        <GameSettingsPlayer
          key={playerId}
          className={classes.item}
          itemTitle={`Player${playerId + 1}`}
          playerId={playerId}
          playerType={player.type}
          playerName={player.name}
          disabled={!isPending}
          onChanged={actions.onPlayerChange}
        />
      ))}
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => {
  return {
    container: css`
      display: flex;
      flex-direction: column;
      justify-content: space-between;
      margin: auto;
    `,
    item: css`
      line-height: 3rem;
    `,
  }
}
