import { DOUBLE_PI } from '../constant'

export interface IGomokuPieceDrawer {
  /**
   * Draw gomoku piece.
   * @param context
   * @param playerId
   * @param x
   * @param y
   * @param radius
   */
  draw(
    context: CanvasRenderingContext2D,
    playerId: number,
    x: number,
    y: number,
    radius: number,
  ): void
}

export interface IGomokuPiecePreferenceSettings {
  pieceStrokeStyle: string
  pieceFillStyle: string
}

export type IPreferenceSettingsProvider = (playerId: number) => IGomokuPiecePreferenceSettings

export const defaultPreferenceSettings: Record<number, IGomokuPiecePreferenceSettings> = {
  0: {
    pieceStrokeStyle: '#000',
    pieceFillStyle: '#111',
  },
  1: {
    pieceStrokeStyle: '#fff',
    pieceFillStyle: '#eee',
  },
}

export class GomokuPieceDrawer implements IGomokuPieceDrawer {
  public readonly getPreferenceSettings: IPreferenceSettingsProvider

  constructor(getPreferenceSettings: IPreferenceSettingsProvider) {
    this.getPreferenceSettings = getPreferenceSettings
  }

  public draw(
    context: CanvasRenderingContext2D,
    playerId: number,
    x: number,
    y: number,
    radius: number,
  ): void {
    const { pieceStrokeStyle, pieceFillStyle } = this.getPreferenceSettings(playerId)
    // eslint-disable-next-line no-param-reassign
    context.strokeStyle = pieceStrokeStyle
    // eslint-disable-next-line no-param-reassign
    context.fillStyle = pieceFillStyle
    context.beginPath()
    context.arc(x, y, radius, 0, DOUBLE_PI, false)
    context.closePath()
    context.stroke()
    context.fill()
  }
}
